import { Link } from 'react-router-dom';
import './Navbar.css';
import { useState } from 'react';

function Navbar() {
  // Use state to trigger re-render when adminAccess changes

  const [adminEnabled, setAdminEnabled] = useState(localStorage.getItem('adminAccess') === 'true');

  const enableAdmin = () => {
    localStorage.setItem('adminAccess', 'true');
    setAdminEnabled(true);
  };

  const disableAdmin = () => {
    localStorage.removeItem('adminAccess');
    setAdminEnabled(false);
  };

  return (
    <nav className="navbar">
      <div className="navbar-brand">
        <span>Market Square</span>
      </div>

      <ul>
        <li><Link to="/">Home</Link></li>
        <li><Link to="/promotions">Promotions</Link></li>
        {/*<li>
          {!adminEnabled ? (
            <button
              onClick={enableAdmin}
              style={{ background: 'none', border: 'none', color: 'blue', cursor: 'pointer', padding: 0 }}
            >
              Enable Admin
            </button>
          ) : (
            <button
              onClick={disableAdmin}
              style={{ background: 'none', border: 'none', color: 'red', cursor: 'pointer', padding: 0 }}
            >
              Disable Admin
            </button>
          )}
        </li>
        {/* Admin link only visible if adminAccess is 'true' */}
        {adminEnabled && (
          <li><Link to="/admin">Admin</Link></li>
        )}
        <li><Link to="/store-locator">Store Locator</Link></li>
        <li><Link to="/cart">Cart</Link></li>
      </ul>

      <div className="search-bar">
        <input type="text" placeholder="Search for products..." />
        <button>Search</button>
      </div>
    </nav>
  );
}
export default Navbar;
